// Parse optimizer output
const output = $input.first().json;
const fs = require('fs');

let results = {
  optimization_type: 'walk_forward',
  pairs_analyzed: $json.pairs,
  timeframe: $json.timeframe,
  recommendations: {},
  best_overall: null,
  worst_overall: null,
  timestamp: new Date().toISOString()
};

try {
  const resultsFile = JSON.parse(fs.readFileSync('/tmp/optimization_results.json', 'utf8'));
  results.raw_results = resultsFile;

  // Find best and worst performers
  let bestSharpe = -Infinity;
  let worstSharpe = Infinity;

  Object.entries(resultsFile).forEach(([pair, data]) => {
    if (data.sharpe_ratio > bestSharpe) {
      bestSharpe = data.sharpe_ratio;
      results.best_overall = { pair, ...data };
    }
    if (data.sharpe_ratio < worstSharpe) {
      worstSharpe = data.sharpe_ratio;
      results.worst_overall = { pair, ...data };
    }
  });
} catch (e) {
  results.error = e.message;
}

return results;

