// Optional: Update config.yaml with best parameters
// This requires manual review for safety
const fs = require('fs');
const yaml = require('js-yaml');

const configPath = '/sessions/busy-awesome-noether/mnt/forex_scalper_bot/config.yaml';

let config = {};
try {
  config = yaml.load(fs.readFileSync(configPath, 'utf8'));
} catch (e) {
  console.log('Config file not found, creating new');
}

// Create updated config with best parameters
const updatedConfig = {
  ...config,
  optimization: {
    last_run: new Date().toISOString(),
    best_pair: $json.best_overall.pair,
    best_params: $json.best_overall.optimal_params || {},
    sharpe_ratio: $json.best_overall.sharpe_ratio,
    recommendations: $json.output
  }
};

// Save as candidate (not auto-applied)
const candidatePath = '/sessions/busy-awesome-noether/mnt/forex_scalper_bot/config_candidate.yaml';
fs.writeFileSync(candidatePath, yaml.dump(updatedConfig));

return { 
  status: 'config_candidate_created',
  path: candidatePath,
  message: 'Review the candidate config before applying'
};

// Save detailed optimization report
const fs = require('fs');
const path = require('path');

const reportDir = '/sessions/busy-awesome-noether/mnt/forex_scalper_bot/optimization_reports';
if (!fs.existsSync(reportDir)) {
  fs.mkdirSync(reportDir, { recursive: true });
}

const filename = path.join(reportDir, `optimization_report_${Date.now()}.json`);
const report = {
  timestamp: $json.timestamp,
  optimization_type: $json.optimization_type,
  pairs_analyzed: $json.pairs_analyzed,
  results: $json.raw_results,
  best_overall: $json.best_overall,
  worst_overall: $json.worst_overall,
  ai_analysis: $json.output
};

fs.writeFileSync(filename, JSON.stringify(report, null, 2));
return { saved_to: filename, status: 'success' };
